import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Limit the input size to 10 characters
        String truncatedInput = input.substring(0, Math.min(input.length(), 10));

        char[] buffer = new char[10];

        // Copy characters from truncatedInput to buffer
        for (int i = 0; i < truncatedInput.length(); i++) {
            buffer[i] = truncatedInput.charAt(i);
        }

        System.out.println("Buffer content: " + new String(buffer));
    }
}

